export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    // CORS headers for public-facing API
    const corsHeaders = {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    };

    // Handle CORS preflight
    if (request.method === 'OPTIONS') {
      return new Response(null, { status: 204, headers: corsHeaders });
    }

    try {
      // Request context passed to internal services
      const requestContext = {
        requestId: crypto.randomUUID(),
        timestamp: Date.now(),
        clientIP: request.headers.get('CF-Connecting-IP'),
        userAgent: request.headers.get('User-Agent'),
        country: request.cf?.country || 'unknown',
      };

      // Attach context as a header for downstream services
      const contextHeaders = new Headers(request.headers);
      contextHeaders.set('X-Request-Context', JSON.stringify(requestContext));

      let response;

      // Route to appropriate internal service based on path
      if (path.startsWith('/api/auth')) {
        response = await routeToService(env.AUTH_SERVICE, request, contextHeaders, '/api/auth');
      } else if (path.startsWith('/api/users')) {
        response = await routeToService(env.USER_SERVICE, request, contextHeaders, '/api/users');
      } else if (path.startsWith('/api/data')) {
        response = await routeToService(env.DATA_SERVICE, request, contextHeaders, '/api/data');
      } else if (path.startsWith('/api/notifications')) {
        response = await routeToService(env.NOTIFICATION_SERVICE, request, contextHeaders, '/api/notifications');
      } else if (path === '/api/health') {
        response = await aggregateHealthChecks(env);
      } else if (path === '/api/aggregate') {
        response = await handleAggregateRequest(request, env, contextHeaders);
      } else {
        response = new Response(JSON.stringify({
          error: 'Not Found',
          message: `No service registered for path: ${path}`,
          availableRoutes: ['/api/auth', '/api/users', '/api/data', '/api/notifications', '/api/health', '/api/aggregate']
        }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      // Clone response to add CORS and tracking headers
      const newHeaders = new Headers(response.headers);
      Object.entries(corsHeaders).forEach(([key, value]) => {
        newHeaders.set(key, value);
      });
      newHeaders.set('X-Request-ID', requestContext.requestId);
      newHeaders.set('X-Gateway-Latency', `${Date.now() - requestContext.timestamp}ms`);

      return new Response(response.body, {
        status: response.status,
        statusText: response.statusText,
        headers: newHeaders,
      });

    } catch (error) {
      return new Response(JSON.stringify({
        error: 'Gateway Error',
        message: error.message,
      }), {
        status: 502,
        headers: { 'Content-Type': 'application/json', ...corsHeaders },
      });
    }
  }
};

async function routeToService(service, originalRequest, contextHeaders, basePath) {
  if (!service) {
    return new Response(JSON.stringify({
      error: 'Service Unavailable',
      message: `The requested service is not configured`,
    }), {
      status: 503,
      headers: { 'Content-Type': 'application/json' },
    });
  }

  const url = new URL(originalRequest.url);
  // Strip the base path prefix so internal services get clean paths
  const internalPath = url.pathname.replace(basePath, '') || '/';
  const internalUrl = new URL(internalPath + url.search, 'http://internal-service');

  const serviceRequest = new Request(internalUrl.toString(), {
    method: originalRequest.method,
    headers: contextHeaders,
    body: originalRequest.method !== 'GET' && originalRequest.method !== 'HEAD'
      ? originalRequest.body
      : undefined,
  });

  return service.fetch(serviceRequest);
}

async function aggregateHealthChecks(env) {
  const services = {
    auth: env.AUTH_SERVICE,
    users: env.USER_SERVICE,
    data: env.DATA_SERVICE,
    notifications: env.NOTIFICATION_SERVICE,
  };

  const healthResults = {};

  await Promise.all(
    Object.entries(services).map(async ([name, service]) => {
      try {
        if (!service) {
          healthResults[name] = { status: 'not_configured' };
          return;
        }
        const response = await service.fetch(new Request('http://internal-service/health'));
        const data = await response.json();
        healthResults[name] = { status: 'healthy', ...data };
      } catch (error) {
        healthResults[name] = { status: 'unhealthy', error: error.message };
      }
    })
  );

  const allHealthy = Object.values(healthResults).every(
    r => r.status === 'healthy' || r.status === 'not_configured'
  );

  return new Response(JSON.stringify({
    gateway: 'healthy',
    services: healthResults,
    overall: allHealthy ? 'healthy' : 'degraded',
    timestamp: new Date().toISOString(),
  }), {
    status: allHealthy ? 200 : 207,
    headers: { 'Content-Type': 'application/json' },
  });
}

// Fan-out: aggregate data from multiple services in a single request
async function handleAggregateRequest(request, env, contextHeaders) {
  if (request.method !== 'POST') {
    return new Response(JSON.stringify({ error: 'Method not allowed' }), {
      status: 405,
      headers: { 'Content-Type': 'application/json' },
    });
  }

  const body = await request.json();
  const { queries } = body;

  if (!queries || !Array.isArray(queries)) {
    return new Response(JSON.stringify({
      error: 'Bad Request',
      message: 'Body must contain a "queries" array',
    }), {
      status: 400,
      headers: { 'Content-Type': 'application/json' },
    });
  }

  const serviceMap = {
    auth: env.AUTH_SERVICE,
    users: env.USER_SERVICE,
    data: env.DATA_SERVICE,
    notifications: env.NOTIFICATION_SERVICE,
  };

  const results = {};

  await Promise.all(
    queries.map(async (query) => {
      const { service, path, method = 'GET', body: queryBody, key } = query;
      const resultKey = key || `${service}:${path}`;

      try {
        const svc = serviceMap[service];
        if (!svc) {
          results[resultKey] = { error: `Service "${service}" not found` };
          return;
        }

        const serviceRequest = new Request(`http://internal-service${path}`, {
          method,
          headers: contextHeaders,
          body: queryBody ? JSON.stringify(queryBody) : undefined,
        });

        const response = await svc.fetch(serviceRequest);
        results[resultKey] = {
          status: response.status,
          data: await response.json(),
        };
      } catch (error) {
        results[resultKey] = { error: error.message };
      }
    })
  );

  return new Response(JSON.stringify({ results }), {
    status: 200,
    headers: { 'Content-Type': 'application/json' },
  });
}


