export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    // Parse request context from gateway
    const requestContext = parseRequestContext(request);

    try {
      // Route handling
      if (path === '/health') {
        return jsonResponse({ service: 'auth', status: 'healthy', uptime: Date.now() });
      }

      if (path === '/login' && method === 'POST') {
        return await handleLogin(request, env, requestContext);
      }

      if (path === '/register' && method === 'POST') {
        return await handleRegister(request, env, requestContext);
      }

      if (path === '/verify' && method === 'POST') {
        return await handleVerifyToken(request, env, requestContext);
      }

      if (path === '/refresh' && method === 'POST') {
        return await handleRefreshToken(request, env, requestContext);
      }

      if (path === '/logout' && method === 'POST') {
        return await handleLogout(request, env, requestContext);
      }

      return jsonResponse({ error: 'Not Found', path }, 404);

    } catch (error) {
      return jsonResponse({
        error: 'Auth Service Error',
        message: error.message,
        requestId: requestContext?.requestId,
      }, 500);
    }
  }
};

function parseRequestContext(request) {
  try {
    const contextHeader = request.headers.get('X-Request-Context');
    return contextHeader ? JSON.parse(contextHeader) : null;
  } catch {
    return null;
  }
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });
}

async function generateToken(payload, secret) {
  const header = btoa(JSON.stringify({ alg: 'HS256', typ: 'JWT' }));
  const body = btoa(JSON.stringify({ ...payload, iat: Date.now(), exp: Date.now() + 3600000 }));
  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey(
    'raw',
    encoder.encode(secret),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign']
  );
  const signature = await crypto.subtle.sign('HMAC', key, encoder.encode(`${header}.${body}`));
  const sig = btoa(String.fromCharCode(...new Uint8Array(signature)));
  return `${header}.${body}.${sig}`;
}

async function handleLogin(request, env, context) {
  const { email, password } = await request.json();

  if (!email || !password) {
    return jsonResponse({ error: 'Email and password are required' }, 400);
  }

  // Look up user in KV store
  const userRecord = await env.AUTH_KV?.get(`user:${email}`, 'json');

  if (!userRecord) {
    return jsonResponse({ error: 'Invalid credentials' }, 401);
  }

  // In production, use proper password hashing (bcrypt via wasm, etc.)
  const passwordHash = await hashPassword(password);
  if (passwordHash !== userRecord.passwordHash) {
    // Log failed attempt
    await env.AUTH_KV?.put(`failed:${email}:${Date.now()}`, JSON.stringify({
      ip: context?.clientIP,
      timestamp: Date.now(),
    }), { expirationTtl: 86400 });

    return jsonResponse({ error: 'Invalid credentials' }, 401);
  }

  const token = await generateToken(
    { userId: userRecord.userId, email, role: userRecord.role },
    env.JWT_SECRET || 'default-secret-change-me'
  );

  const refreshToken = crypto.randomUUID();
  await env.AUTH_KV?.put(`refresh:${refreshToken}`, JSON.stringify({
    userId: userRecord.userId,
    email,
    createdAt: Date.now(),
  }), { expirationTtl: 604800 }); // 7 days

  // Notify user service about login event via service binding
  if (env.USER_SERVICE) {
    ctx?.waitUntil?.(
      env.USER_SERVICE.fetch(new Request('http://internal-service/events/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          userId: userRecord.userId,
          ip: context?.clientIP,
          country: context?.country,
          timestamp: Date.now(),
        }),
      })).catch(() => {}) // Fire and forget
    );
  }

  return jsonResponse({
    token,
    refreshToken,
    user: { userId: userRecord.userId, email, role: userRecord.role },
  });
}

async function handleRegister(request, env, context) {
  const { email, password, name } = await request.json();

  if (!email || !password || !name) {
    return jsonResponse({ error: 'Email, password, and name are required' }, 400);
  }

  const existing = await env.AUTH_KV?.get(`user:${email}`);
  if (existing) {
    return jsonResponse({ error: 'User already exists' }, 409);
  }

  const userId = crypto.randomUUID();
  const passwordHash = await hashPassword(password);

  await env.AUTH_KV?.put(`user:${email}`, JSON.stringify({
    userId,
    email,
    passwordHash,
    role: 'user',
    createdAt: Date.now(),
  }));

  // Create user profile in user service via service binding
  if (env.USER_SERVICE) {
    const profileResponse = await env.USER_SERVICE.fetch(
      new Request('http://internal-service/profiles', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId, email, name }),
      })
    );

    if (!profileResponse.ok) {
      // Rollback auth record on profile creation failure
      await env.AUTH_KV?.delete(`user:${email}`);
      return jsonResponse({ error: 'Failed to create user profile' }, 500);
    }
  }

  // Send welcome notification via notification service
  if (env.NOTIFICATION_SERVICE) {
    env.NOTIFICATION_SERVICE.fetch(
      new Request('http://internal-service/send', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          type: 'welcome',
          userId,
          email,
          data: { name },
        }),
      })
    ).catch(() => {}); // Fire and forget
  }

  const token = await generateToken(
    { userId, email, role: 'user' },
    env.JWT_SECRET || 'default-secret-change-me'
  );

  return jsonResponse({ token, user: { userId, email, name, role: 'user' } }, 201);
}

